                                        <span class="text-surface-900 font-medium text-sm">{{ selectedProduct().rating }}</span>
                                        <i class="pi pi-star-fill text-yellow-500"></i>
                                    </div>
                                </div>
                            </div>
                            <div class="flex gap-2">
                                <vx-button
                                    icon="pi pi-shopping-cart"
                                    [label]="'Buy Now | $' + selectedProduct().price"
                                    [disabled]="selectedProduct().inventoryStatus === 'OUTOFSTOCK'"
                                    class="flex-auto"
                                    styleClass="w-full whitespace-nowrap"
                                    (onClick)="hidePopover()"
                                />
                                <vx-button icon="pi pi-heart" outlined (onClick)="hidePopover()" />
                            </div>
                        </div>
                    </div>
                </ng-template>
            </vx-popover>
        </div>
    `,
    standalone: true,
    imports: [],
    providers: [ProductService, MessageService]
})
export class PopoverDatatableDemo implements OnInit {
    private productService = inject(ProductService);
    private messageService = inject(MessageService);
    products = signal<Product[]>([]);
    selectedProduct = signal<Product | null>(null);

    ngOnInit() {
        this.productService.getProductsSmall().then((products) => {
            this.products.set(products);
        });
    }

    displayProduct(event, product) {
        if (this.selectedProduct()?.id === product.id) {
            this.op.hide();
            this.selectedProduct.set(null);
        } else {
            this.selectedProduct.set(product);
            this.op.show(event);

            if (this.op.container) {
                this.op.align();
            }
        }
    }

    hidePopover() {
        this.op.hide();
    }

    getSeverity(product) {
        switch (product.inventoryStatus) {
            case 'INSTOCK':
                return 'success';

            case 'LOWSTOCK':
                return 'warn';

            case 'OUTOFSTOCK':
                return 'danger';

            default:
                return null;
        }
    }
}

